import { executorAbi } from "executooor-viem";
import nock from "nock";
import { erc20Abi, parseUnits } from "viem";
import { readContract, writeContract } from "viem/actions";
import { describe, expect } from "vitest";

import { USDC, wstETH } from "../constants.js";
import { ZeroExTest } from "../helpers.js";
import { zeroExTest } from "../setup.js";

// Captured live from `GET https://api.0x.org/swap/allowance-holder/quote`
// (chainId=1, 1 wstETH -> USDC, slippageBps=100, taker=encoder.address) at mainnet block 25_352_408.
// The fork block is pinned to this response block so the on-chain state matches the route, and the
// encoder address (0x40d8...5931) — baked into the calldata — matches the contract the fixture deploys.
const allowanceHolder = "0x0000000000001ff3684f28c67538d4d072c22734";
const expectedTaker = "0x40d8d1afeed9f58b78e70c0e2c0e80008f3e5931";
const buyAmount = 2_103_390_175n;
const minBuyAmount = 2_082_324_675n;
const calldata =
  "";

describe("zeroEx liquidity venue", () => {
  const liquidityVenue = new ZeroExTest([1]);

  zeroExTest.sequential("should test supportsRoute", ({ encoder }) => {
    expect(liquidityVenue.supportsRoute(encoder, wstETH, USDC)).toBe(true);
  });

  zeroExTest.sequential("should execute swap via AllowanceHolder", async ({ encoder }) => {
    // Sanity: the captured calldata embeds this taker. Fixture must deploy the executor here.
    expect(encoder.address.toLowerCase()).toBe(expectedTaker);

    encoder
      .erc20Approve(wstETH, allowanceHolder, parseUnits("1", 18))
      .pushCall(allowanceHolder, 0n, calldata);

    const expectedCalls = encoder.flush();

    nock("https://api.0x.org")
      .get("/swap/allowance-holder/quote")
      .query(true)
      .reply(200, {
        liquidityAvailable: true,
        sellAmount: "1000000000000000000",
        buyAmount: buyAmount.toString(),
        minBuyAmount: minBuyAmount.toString(),
        issues: {
          allowance: { actual: "0", spender: allowanceHolder },
          balance: null,
        },
        transaction: {
          to: allowanceHolder,
          data: calldata,
          value: "0",
          gas: "374012",
          gasPrice: "508450620",
        },
      });

    await liquidityVenue.convert(encoder, {
      src: wstETH,
      dst: USDC,
      srcAmount: parseUnits("1", 18),
    });

    const encodedCalls = encoder.flush();

    expect(encodedCalls).toEqual(expectedCalls);

    await encoder.client.deal({
      erc20: wstETH,
      account: encoder.address,
      amount: parseUnits("1", 18),
    });

    const [usdcBefore, wstETHBefore] = await Promise.all([
      readContract(encoder.client, {
        address: USDC,
        abi: erc20Abi,
        functionName: "balanceOf",
        args: [encoder.address],
      }),
      readContract(encoder.client, {
        address: wstETH,
        abi: erc20Abi,
        functionName: "balanceOf",
        args: [encoder.address],
      }),
    ]);

    expect(usdcBefore).toBe(0n);
    expect(wstETHBefore).toBe(parseUnits("1", 18));

    await writeContract(encoder.client, {
      address: encoder.address,
      abi: executorAbi,
      functionName: "exec_606BaXt",
      args: [encodedCalls],
    });

    const [usdcAfter, wstETHAfter] = await Promise.all([
      readContract(encoder.client, {
        address: USDC,
        abi: erc20Abi,
        functionName: "balanceOf",
        args: [encoder.address],
      }),
      readContract(encoder.client, {
        address: wstETH,
        abi: erc20Abi,
        functionName: "balanceOf",
        args: [encoder.address],
      }),
    ]);

    expect(usdcAfter).toBeGreaterThanOrEqual(minBuyAmount);
    expect(wstETHAfter).toBe(0n);
  });
});
